      var barY = leaderboardListRect.y + 10 + (leaderboardListRect.h - 20 - barH) * (leaderboardState.scrollY / maxScroll);
      fillRoundRect(leaderboardListRect.x + leaderboardListRect.w - 9, barY, 5, barH, 3, "rgba(255,242,59,0.72)");
