    context.lineTo(26, -3);
    context.lineTo(17, 0);
    context.lineTo(14, 9);
    context.lineTo(11, 0);
    context.lineTo(2, -3);
    context.lineTo(11, -6);
    context.closePath();
    context.fill();
    context.stroke();

    context.fillStyle = "#fff23b";
    context.beginPath();
    context.moveTo(0, -18);
    context.lineTo(4, -8);
    context.lineTo(15, -6);
    context.lineTo(6, 1);
    context.lineTo(8, 12);
    context.lineTo(0, 6);
    context.lineTo(-8, 12);
    context.lineTo(-6, 1);
    context.lineTo(-15, -6);
    context.lineTo(-4, -8);
    context.closePath();
    context.fill();
    context.stroke();
    context.restore();
